class TrimDialog(QtWidgets.QDialog):
    """
    Dialog that asks for:
      - Trim Start (seconds to remove from the beginning)
      - Trim End   (seconds to remove from the end)
    Returns (start_trim, end_trim) if accepted, or raises ValueError if invalid.
    """
    def __init__(self, parent=None, max_duration=0.0):
        super().__init__(parent)
        self.log_current_page = 0
        self.log_entries_per_page = 50
        
        self.setWindowTitle("Trim WAV File")
        self.setModal(True)

        # Line edits for “seconds to trim from start” and “seconds to trim from end”
        self.start_edit = QtWidgets.QLineEdit("0.0")
        self.end_edit   = QtWidgets.QLineEdit("0.0")
        self.start_edit.setFixedWidth(80)
        self.end_edit.setFixedWidth(80)

        form = QtWidgets.QFormLayout()
        form.addRow("Trim Start (s):", self.start_edit)
        form.addRow("Trim End   (s):", self.end_edit)

        # Show the total file duration for reference
        info = QtWidgets.QLabel(f"(File length ≈ {max_duration:.2f} s)")
        form.addRow(info)

        # OK / Cancel buttons
        btn_box = QtWidgets.QDialogButtonBox(
            QtWidgets.QDialogButtonBox.Ok | QtWidgets.QDialogButtonBox.Cancel
        )
        btn_box.accepted.connect(self.accept)
        btn_box.rejected.connect(self.reject)

        vbox = QtWidgets.QVBoxLayout(self)
        vbox.addLayout(form)
        vbox.addWidget(btn_box)

    def values(self):
        """
        Parse and return (start_trim, end_trim) as floats.
        Raises ValueError if the text cannot be converted.
        """
        start = float(self.start_edit.text())
        end   = float(self.end_edit.text())
        return start, end
    

# ---------------------
# PyQt5 Application Classes
# ---------------------

# ---------------------------------------------------
# Annotation Review Dialog (label + playback + FFT)
# ---------------------------------------------------
class AnnotationReviewDialog(QtWidgets.QDialog):
    """
    Review a spectrogram annotation:
      - choose/override label from call library candidates
      - play/pause/stop the corresponding audio segment
      - view FFT of the segment with editable axis limits
      - optionally add a new call-profile to the library (global or project)
    """
    def __init__(
        self,
        parent,
        ann_id: int,
        spectrogram_id: int,
        project_id,
        wav_path: str,
        sample_rate: float,
        channel_index: int,
        x0: float, x1: float, y0: float, y1: float,
        current_label: str,
        candidates: list,
    ):
        super().__init__(parent)
        self.setWindowTitle("Annotation Review")
        self.setModal(True)

        self.ann_id = int(ann_id)
        self.spectrogram_id = int(spectrogram_id)
        self.project_id = project_id
        self.wav_path = wav_path or ""
        self.fs = float(sample_rate or 0.0)
        self.channel_index = int(channel_index or 0)
        self.x0 = float(x0); self.x1 = float(x1)
        self.y0 = float(y0); self.y1 = float(y1)
        self.current_label = current_label or ""
        self.candidates = candidates or []

        self._segment = None
        self._sd = None
        self._stream = None
        self._play_pos = 0
        self._playing = False

        # ---- Layout ----
        root = QtWidgets.QHBoxLayout(self)

        # Left: labeling
        left = QtWidgets.QVBoxLayout()
        info = QtWidgets.QLabel(
            f"Time: {self.x0:0.4f}–{self.x1:0.4f} s   |   "
            f"Freq: {self.y0:0.1f}–{self.y1:0.1f} Hz   |   "
            f"Dur: {max(0.0, self.x1-self.x0):0.4f} s"
        )
        left.addWidget(info)

        left.addWidget(QtWidgets.QLabel("Suggested labels:"))
        self.cand_list = QtWidgets.QListWidget()
        for c in self.candidates:
            # candidates are dicts from _suggest_labels_for_box
            name = c.get("name", "")
            scope = c.get("scope", "")
            score = c.get("score", 0.0)
            why = c.get("why", "")
            it = QtWidgets.QListWidgetItem(f"{name} [{scope}]  score={score:0.2f}  {why}")
            it.setData(QtCore.Qt.UserRole, name)
            self.cand_list.addItem(it)
        self.cand_list.itemDoubleClicked.connect(self._apply_selected_candidate)
        left.addWidget(self.cand_list, 1)

        left.addWidget(QtWidgets.QLabel("Label override:"))
        self.label_edit = QtWidgets.QLineEdit(self.current_label)
        left.addWidget(self.label_edit)

        btn_row = QtWidgets.QHBoxLayout()
        self.apply_btn = QtWidgets.QPushButton("Apply Label")
        self.apply_btn.clicked.connect(self._apply_label)
        btn_row.addWidget(self.apply_btn)

        self.clear_btn = QtWidgets.QPushButton("Clear")
        self.clear_btn.clicked.connect(self._clear_label)
        btn_row.addWidget(self.clear_btn)
        left.addLayout(btn_row)

        prof_row = QtWidgets.QHBoxLayout()
        self.add_profile_btn = QtWidgets.QPushButton("Add Profile From Box")
        self.add_profile_btn.clicked.connect(self._add_profile_from_box)
        prof_row.addWidget(self.add_profile_btn)

        self.scope_combo = QtWidgets.QComboBox()
        self.scope_combo.addItems(["Project", "Global"])
        prof_row.addWidget(QtWidgets.QLabel("Save as:"))
        prof_row.addWidget(self.scope_combo)
        left.addLayout(prof_row)

        self.close_btn = QtWidgets.QPushButton("Close")
        self.close_btn.clicked.connect(self.accept)
        left.addWidget(self.close_btn)

        root.addLayout(left, 2)

        # Right: playback + FFT
        right = QtWidgets.QVBoxLayout()

        # Playback controls
        play_box = QtWidgets.QGroupBox("Playback")
        play_l = QtWidgets.QHBoxLayout(play_box)
        self.play_btn = QtWidgets.QPushButton("Play")
        self.play_btn.clicked.connect(self._toggle_play_pause)
        play_l.addWidget(self.play_btn)
        self.stop_btn = QtWidgets.QPushButton("Stop")
        self.stop_btn.clicked.connect(self._stop)
        play_l.addWidget(self.stop_btn)
        self.play_status = QtWidgets.QLabel("")
        play_l.addWidget(self.play_status, 1)
        right.addWidget(play_box)

        # FFT plot
        fft_box = QtWidgets.QGroupBox("FFT")
        fft_v = QtWidgets.QVBoxLayout(fft_box)

        self.fft_fig = Figure(figsize=(5, 3), dpi=100, facecolor="#000000")
        self.fft_ax = self.fft_fig.add_subplot(111)
        self.fft_ax.set_facecolor("#000000")
        self.fft_ax.tick_params(colors="white")
        for sp in self.fft_ax.spines.values():
            sp.set_edgecolor("white")
        self.fft_canvas = FigureCanvas(self.fft_fig)
        fft_v.addWidget(self.fft_canvas, 1)

        # Axis controls
        ax_grid = QtWidgets.QGridLayout()
        self.xmin_edit = QtWidgets.QLineEdit("")
        self.xmax_edit = QtWidgets.QLineEdit("")
        self.ymin_edit = QtWidgets.QLineEdit("")
        self.ymax_edit = QtWidgets.QLineEdit("")
        for w in (self.xmin_edit, self.xmax_edit, self.ymin_edit, self.ymax_edit):
            w.setFixedWidth(90)

        ax_grid.addWidget(QtWidgets.QLabel("X min (Hz)"), 0, 0); ax_grid.addWidget(self.xmin_edit, 0, 1)
        ax_grid.addWidget(QtWidgets.QLabel("X max (Hz)"), 0, 2); ax_grid.addWidget(self.xmax_edit, 0, 3)
        ax_grid.addWidget(QtWidgets.QLabel("Y min (dB)"), 1, 0); ax_grid.addWidget(self.ymin_edit, 1, 1)
        ax_grid.addWidget(QtWidgets.QLabel("Y max (dB)"), 1, 2); ax_grid.addWidget(self.ymax_edit, 1, 3)

        self.use_box_freq_btn = QtWidgets.QPushButton("Use Box Freq Range")
        self.use_box_freq_btn.clicked.connect(self._use_box_freq_range)
        ax_grid.addWidget(self.use_box_freq_btn, 2, 0, 1, 2)

        self.update_fft_btn = QtWidgets.QPushButton("Update FFT")
        self.update_fft_btn.clicked.connect(self._update_fft)
        ax_grid.addWidget(self.update_fft_btn, 2, 2, 1, 2)

        fft_v.addLayout(ax_grid)
        right.addWidget(fft_box, 1)

        root.addLayout(right, 3)

        # Load segment + initial FFT
        self._load_segment()
        self._update_fft()

    # ---------------- Playback ----------------
    def _load_segment(self):
        self._segment = None
        self._play_pos = 0
        self._playing = False
        self.play_btn.setText("Play")
        self.play_status.setText("")

        if not self.wav_path or not os.path.exists(self.wav_path):
            self.play_status.setText("WAV not found.")
            self.play_btn.setEnabled(False)
            self.stop_btn.setEnabled(False)
            return

        try:
            info = sf.info(self.wav_path)
            fs = float(info.samplerate)
            if fs > 0:
                self.fs = fs
        except Exception:
            pass

        if not self.fs or self.fs <= 0:
            self.play_status.setText("Unknown sample rate.")
            self.play_btn.setEnabled(False)
            self.stop_btn.setEnabled(False)
            return

        try:
            i0 = max(0, int(round(self.x0 * self.fs)))
            i1 = max(i0 + 1, int(round(self.x1 * self.fs)))
            with sf.SoundFile(self.wav_path, mode="r") as f:
                if i0 >= len(f):
                    self.play_status.setText("Segment out of range.")
                    self.play_btn.setEnabled(False)
                    self.stop_btn.setEnabled(False)
                    return
                f.seek(i0)
                frames = min(i1 - i0, len(f) - i0)
                data = f.read(frames, dtype="float32", always_2d=True)
            ch = max(0, min(self.channel_index, data.shape[1] - 1))
            seg = data[:, ch].astype("float32", copy=False)
            # Tiny fade to avoid clicks
            nfade = min(256, max(1, len(seg)//50))
            if len(seg) > 2*nfade:
                w = np.linspace(0.0, 1.0, nfade, dtype=np.float32)
                seg[:nfade] *= w
                seg[-nfade:] *= w[::-1]
            self._segment = seg
            self.play_btn.setEnabled(True)
            self.stop_btn.setEnabled(True)
        except Exception as e:
            self.play_status.setText(f"Failed to load audio: {e}")
            self.play_btn.setEnabled(False)
            self.stop_btn.setEnabled(False)

    def _ensure_sounddevice(self):
        if self._sd is not None:
            return True
        try:
            import sounddevice as sd
            self._sd = sd
            return True
        except Exception as e:
            self.play_status.setText(f"Playback disabled (sounddevice): {e}")
            return False

    def _toggle_play_pause(self):
        if self._segment is None or len(self._segment) == 0:
            return
        if not self._ensure_sounddevice():
            return

        if self._playing:
            self._pause()
        else:
            self._play()

    def _play(self):
        if self._segment is None or len(self._segment) == 0:
            return
        if not self._ensure_sounddevice():
            return

        sd = self._sd
        seg = self._segment

        def callback(outdata, frames, time_info, status):
            if status:
                pass
            start = self._play_pos
            end = min(start + frames, len(seg))
            chunk = seg[start:end]
            if len(chunk) < frames:
                out = np.zeros((frames,), dtype=np.float32)
                out[: len(chunk)] = chunk
                outdata[:] = out.reshape(-1, 1)
                # stop at end
                self._play_pos = len(seg)
                raise sd.CallbackStop()
            outdata[:] = chunk.reshape(-1, 1)
            self._play_pos = end

        try:
            self._stream = sd.OutputStream(
                samplerate=self.fs,
                channels=1,
                dtype="float32",
                callback=callback,
                finished_callback=self._on_play_finished,
            )
            self._stream.start()
            self._playing = True
            self.play_btn.setText("Pause")
            self.play_status.setText("Playing…")
        except Exception as e:
            self.play_status.setText(f"Playback error: {e}")
            self._playing = False
            self.play_btn.setText("Play")

    def _pause(self):
        try:
            if self._stream is not None:
                self._stream.stop()
                self._stream.close()
        except Exception:
            pass
        self._stream = None
        self._playing = False
        self.play_btn.setText("Play")
        self.play_status.setText("Paused")

    def _stop(self):
        try:
            if self._stream is not None:
                self._stream.stop()
                self._stream.close()
        except Exception:
            pass
        self._stream = None
        self._play_pos = 0
        self._playing = False
        self.play_btn.setText("Play")
        self.play_status.setText("Stopped")

    def _on_play_finished(self):
        # Called by sounddevice thread after callback stop
        QtCore.QTimer.singleShot(0, self._on_play_finished_ui)

    def _on_play_finished_ui(self):
        self._stream = None
        self._playing = False
        self.play_btn.setText("Play")
        if self._segment is not None and self._play_pos >= len(self._segment):
            self.play_status.setText("Finished")
        else:
            self.play_status.setText("")

    def closeEvent(self, event):
        try:
            self._stop()
        except Exception:
            pass
        super().closeEvent(event)

    # ---------------- FFT ----------------
    def _use_box_freq_range(self):
        self.xmin_edit.setText(f"{min(self.y0, self.y1):0.1f}")
        self.xmax_edit.setText(f"{max(self.y0, self.y1):0.1f}")
        self._update_fft()

    def _update_fft(self):
        self.fft_ax.clear()
        self.fft_ax.set_facecolor("#000000")
        self.fft_ax.tick_params(colors="white")
        for sp in self.fft_ax.spines.values():
            sp.set_edgecolor("white")

        if self._segment is None or len(self._segment) < 8 or not self.fs:
            self.fft_ax.text(0.5, 0.5, "No audio segment", color="white",
                             ha="center", va="center", transform=self.fft_ax.transAxes)
            self.fft_canvas.draw_idle()
            return

        x = self._segment.astype(float)
        x = x - np.mean(x)
        w = np.hanning(len(x))
        X = np.fft.rfft(x * w)
        f = np.fft.rfftfreq(len(x), d=1.0 / self.fs)
        mag = np.abs(X)
        mag_db = 20.0 * np.log10(np.maximum(mag, 1e-12))

        self.fft_ax.plot(f, mag_db, lw=1.0)
        self.fft_ax.set_xlabel("Frequency (Hz)", color="white")
        self.fft_ax.set_ylabel("Magnitude (dB)", color="white")
        self.fft_ax.set_title("FFT", color="white")

        # Apply axis limits if provided
        def _flt(s):
            s = (s or "").strip()
            if not s:
                return None
            try:
                return float(s)
            except Exception:
                return None

        xmin = _flt(self.xmin_edit.text())
        xmax = _flt(self.xmax_edit.text())
        ymin = _flt(self.ymin_edit.text())
        ymax = _flt(self.ymax_edit.text())

        if xmin is not None or xmax is not None:
            self.fft_ax.set_xlim(
                xmin if xmin is not None else float(np.min(f)),
                xmax if xmax is not None else float(np.max(f)),
            )
        if ymin is not None or ymax is not None:
            self.fft_ax.set_ylim(
                ymin if ymin is not None else float(np.min(mag_db)),
                ymax if ymax is not None else float(np.max(mag_db)),
            )

        self.fft_canvas.draw_idle()

    # ---------------- Labeling / DB ----------------
    def _apply_selected_candidate(self, item):
        try:
            name = item.data(QtCore.Qt.UserRole)
            if name:
                self.label_edit.setText(str(name))
                self._apply_label()
        except Exception:
            pass

    def _apply_label(self):
        lbl = (self.label_edit.text() or "").strip()
        conn = sqlite3.connect(DB_FILENAME)
        cur = conn.cursor()
        cur.execute("UPDATE spectrogram_annotations SET label=? WHERE id=?", (lbl, self.ann_id))
        conn.commit()
        conn.close()
        self.current_label = lbl

    def _clear_label(self):
        self.label_edit.setText("")
        self._apply_label()

    def _add_profile_from_box(self):
        name, ok = QtWidgets.QInputDialog.getText(self, "Profile Name", "Enter a name for this call/profile:")
        if not ok or not name.strip():
            return
        name = name.strip()

        # widen defaults slightly
        fmin = float(min(self.y0, self.y1))
        fmax = float(max(self.y0, self.y1))
        dur = max(0.0, float(self.x1 - self.x0))
        min_dur = max(0.0, dur * 0.8)
        max_dur = max(min_dur, dur * 1.2)

        scope = self.scope_combo.currentText()
        pid = None
        if scope == "Project":
            pid = self.project_id

        notes, ok2 = QtWidgets.QInputDialog.getMultiLineText(self, "Notes", "Optional notes:", "")
        if not ok2:
            notes = ""

        conn = sqlite3.connect(DB_FILENAME)
        cur = conn.cursor()
        cur.execute(
            "INSERT INTO marine_call_library (project_id, name, fmin_hz, fmax_hz, min_duration_s, max_duration_s, notes) "
            "VALUES (?, ?, ?, ?, ?, ?, ?)",
            (pid, name, fmin, fmax, min_dur, max_dur, notes),
        )
        conn.commit()
        conn.close()


class MplCanvas(FigureCanvas):
    def __init__(self, parent=None, width=8, height=4, dpi=100):
        self.fig = plt.Figure(figsize=(width, height), dpi=dpi, facecolor="#000000")
        self.ax = self.fig.add_subplot(111)
        self.ax.set_facecolor("#000000")
        self.ax.tick_params(axis="x", colors="white")
        self.ax.tick_params(axis="y", colors="white")
        self.ax.title.set_color("white")
        self.ax.xaxis.label.set_color("white")
        self.ax.yaxis.label.set_color("white")
        for spine in self.ax.spines.values():
            spine.set_edgecolor("white")
        super().__init__(self.fig)
        self.setParent(parent)
        plt.tight_layout()
# --- Ensure ChannelSelectorDialog is defined early ---
try:
    ChannelSelectorDialog
except NameError:
    from PyQt5 import QtWidgets

    class ChannelSelectorDialog(QtWidgets.QDialog):
        """Configure per-channel acquisition roles and scaling."""

        MODES = [
            ("Raw Voltage", "raw"),
            ("Hydrophone", "hydrophone"),
            ("Voltage Probe", "voltage_probe"),
            ("Current Probe", "current_probe"),
        ]

        def __init__(self, parent, channel_names, mask, configs=None, hydrophone_curves=None):
            super().__init__(parent)
            self.setWindowTitle("Select Channels")
            self.setModal(True)
            self._rows = []
            hydrophone_curves = hydrophone_curves or {}
            configs = configs or []

            layout = QtWidgets.QVBoxLayout(self)
            grid = QtWidgets.QGridLayout()
            grid.addWidget(QtWidgets.QLabel("Use"), 0, 0)
            grid.addWidget(QtWidgets.QLabel("Channel"), 0, 1)
            grid.addWidget(QtWidgets.QLabel("Name"), 0, 2)
            grid.addWidget(QtWidgets.QLabel("Type"), 0, 3)
            grid.addWidget(QtWidgets.QLabel("Hydrophone"), 0, 4)
            grid.addWidget(QtWidgets.QLabel("Distance (m)"), 0, 5)
            grid.addWidget(QtWidgets.QLabel("Depth (m)"), 0, 6)
            grid.addWidget(QtWidgets.QLabel("Scale"), 0, 7)

            for i, name in enumerate(channel_names):
                row_cfg = configs[i] if i < len(configs) else {}
                enabled = mask[i] if i < len(mask) else True

                enable_cb = QtWidgets.QCheckBox()
                enable_cb.setChecked(enabled)

                name_edit = QtWidgets.QLineEdit()
                prior_name = row_cfg.get("name") if isinstance(row_cfg, dict) else None
                name_edit.setText(prior_name or name)
                name_edit.setPlaceholderText(name)

                type_combo = QtWidgets.QComboBox()
                for label, val in self.MODES:
                    type_combo.addItem(label, val)
                initial_mode = row_cfg.get("mode") if isinstance(row_cfg, dict) else None
                if initial_mode:
                    idx = max(0, type_combo.findData(initial_mode))
                    type_combo.setCurrentIndex(idx)

                hydro_combo = QtWidgets.QComboBox()
                hydro_combo.addItem("None", None)
                for curve in hydrophone_curves.values():
                    hydro_combo.addItem(curve.get("curve_name", ""), curve.get("curve_name"))
                if isinstance(row_cfg, dict) and row_cfg.get("hydrophone_curve"):
                    idx = hydro_combo.findData(row_cfg.get("hydrophone_curve"))
                    if idx >= 0:
                        hydro_combo.setCurrentIndex(idx)

                dist_edit = QtWidgets.QLineEdit()
                dist_val = row_cfg.get("distance") if isinstance(row_cfg, dict) else None
                dist_edit.setText("" if dist_val in (None, "") else str(dist_val))
                dist_edit.setPlaceholderText("Optional")

                depth_edit = QtWidgets.QLineEdit()
                depth_val = row_cfg.get("depth") if isinstance(row_cfg, dict) else None
                depth_edit.setText("" if depth_val in (None, "") else str(depth_val))
                depth_edit.setPlaceholderText("Optional")

                scale_edit = QtWidgets.QLineEdit()
                scale_val = row_cfg.get("scale") if isinstance(row_cfg, dict) else None
                scale_edit.setText("" if scale_val in (None, "") else str(scale_val))
                scale_edit.setPlaceholderText("e.g. 100 for 1:100")

                self._rows.append(
                    {
                        "enable": enable_cb,
                        "name": name_edit,
                        "type": type_combo,
                        "hydro": hydro_combo,
                        "dist": dist_edit,
                        "depth": depth_edit,
                        "scale": scale_edit,
                    }
                )

                grid.addWidget(enable_cb, i + 1, 0)
                grid.addWidget(QtWidgets.QLabel(name), i + 1, 1)
                grid.addWidget(name_edit, i + 1, 2)
                grid.addWidget(type_combo, i + 1, 3)
                grid.addWidget(hydro_combo, i + 1, 4)
                grid.addWidget(dist_edit, i + 1, 5)
                grid.addWidget(depth_edit, i + 1, 6)
                grid.addWidget(scale_edit, i + 1, 7)

                def _on_mode_change(idx, row= self._rows[-1]):
                    mode = row["type"].itemData(idx)
                    is_hydro = mode == "hydrophone"
                    is_probe = mode in ("voltage_probe", "current_probe")
                    row["hydro"].setEnabled(is_hydro)
                    row["dist"].setEnabled(is_hydro)
                    row["depth"].setEnabled(is_hydro)
                    row["scale"].setEnabled(is_probe)

                type_combo.currentIndexChanged.connect(_on_mode_change)
                _on_mode_change(type_combo.currentIndex())

            layout.addLayout(grid)
            btns = QtWidgets.QDialogButtonBox(
                QtWidgets.QDialogButtonBox.Ok | QtWidgets.QDialogButtonBox.Cancel
            )
            btns.accepted.connect(self.accept)
            btns.rejected.connect(self.reject)
            layout.addWidget(btns)

        def mask(self):
            return [row["enable"].isChecked() for row in self._rows]

        def names(self):
            names = []
            for idx, row in enumerate(self._rows):
                txt = row["name"].text().strip()
                names.append(txt if txt else f"Ch {idx+1}")
            return names

        def configs(self):
            out = []
            for row in self._rows:
                out.append(
                    {
                        "mode": row["type"].currentData(),
                        "hydrophone_curve": row["hydro"].currentData(),
                        "distance": row["dist"].text(),
                        "depth": row["depth"].text(),
                        "scale": row["scale"].text(),
                        "name": row["name"].text(),
                    }
                )
            return out



class MainWindow(QtWidgets.QMainWindow):

    def _ensure_main_axis(self):
        """
        Make sure the main waveform axis exists on the analysis canvas.

        • In normal (non-FFT) mode: ONE axis (ax_main) filling the canvas.
        • In FFT mode: DON’T touch the layout – just reuse ax_waveform that
          enter_fft_mode() created.
        """
        # We expect setup_analysis_tab() to have created self.canvas already
        canvas = getattr(self, "canvas", None)
        if canvas is None:
            return None

        # MplCanvas uses .fig, plain FigureCanvas uses .figure
        fig = getattr(canvas, "fig", None) or getattr(canvas, "figure", None)
        if fig is None:
            return None

        # If we're in FFT mode, we already have a 2-row layout (ax_waveform + ax_fft)
        if getattr(self, "fft_mode", False):
            ax_wf = getattr(self, "ax_waveform", None)
            if ax_wf is None:
                # Fallback: if something weird happened, use the first axis
                if fig.axes:
                    ax_wf = fig.axes[0]
                else:
                    ax_wf = fig.add_subplot(211)
            self.ax_main = ax_wf
            return ax_wf

        # --- Normal waveform-only mode: exactly ONE axis ---

        # If ax_main is missing or no longer in this figure, rebuild as a single subplot
        if getattr(self, "ax_main", None) is None or self.ax_main not in fig.axes:
            fig.clear()
            self.ax_main = fig.add_subplot(111, facecolor="black")
            self.ax_main.tick_params(colors="white")
            for sp in self.ax_main.spines.values():
                sp.set_edgecolor("white")

            # When we go back to single-plot mode, forget any old FFT axis
            self.ax_fft = None

        return self.ax_main



    def update_main_waveform_plot(self):
        """
        Draw the raw waveform (top graph).

        • Handles mono and multi-channel.
        • Respects selected channels (channel selector / channel_mask).
        • Downsamples for speed.
        • For multi-channel, uses stacked lanes so each channel gets its own “track”
          and each channel gets its own color from self.color_options, starting
          from the currently-selected graph color.
        """
        import numpy as np

        # Ensure axis exists
        ax = self._ensure_main_axis()
        if ax is None:
            return

        ax = self.ax_main
        ax.clear()
        ax.set_facecolor("black")

        # --- Sample rate + data ---
        sr = None
        for k in ("sample_rate", "samplerate", "sr"):
            v = getattr(self, k, None)
            if isinstance(v, (int, float)) and v > 0:
                sr = int(v)
                break

        data = getattr(self, "full_data", None)

        if sr is None or data is None or getattr(data, "size", 0) == 0:
            ax.text(
                0.5,
                0.5,
                "No audio loaded",
                color="white",
                ha="center",
                va="center",
                transform=ax.transAxes,
            )
            try:
                self.canvas.draw_idle()
            except Exception:
                self.canvas.draw()
            return

        # --- Which channels should we draw? ---
        def _selected():
            if hasattr(self, "selected_channel_indices") and callable(
                self.selected_channel_indices
            ):
                sel = self.selected_channel_indices()
                if sel:
                    return [int(x) for x in sel]
            # fallback: all channels if multich, else [0]
            if getattr(data, "ndim", 1) > 1:
                return list(range(data.shape[1]))
            return [0]

        sel = _selected()

        # --- Standardize shape to (N, C) ---
        if getattr(data, "ndim", 1) == 1:
            X = np.asarray(data).reshape(-1, 1)
        else:
            X = np.asarray(data)
            if X.ndim != 2:
                ax.text(
                    0.5,
                    0.5,
                    "Unsupported data shape",
                    color="white",
                    ha="center",
                    va="center",
                    transform=ax.transAxes,
                )
                try:
                    self.canvas.draw_idle()
                except Exception:
                    self.canvas.draw()
                return

        # --- Keep only valid channels ---
        C = X.shape[1]
        sel = [ch for ch in sel if 0 <= ch < C]
        if not sel:
            ax.text(
                0.5,
                0.5,
                "No channels selected",
                color="white",
                ha="center",
                va="center",
                transform=ax.transAxes,
            )
            try:
                self.canvas.draw_idle()
            except Exception:
                self.canvas.draw()
            return

        # --- Time axis + decimation ---
        N = X.shape[0]
        t = np.arange(N, dtype=float) / float(sr)

        # Keep ~200k points total across all channels
        max_pts = 200_000
        step = int(np.ceil(max(1, N * max(1, len(sel)) / max_pts)))
        if step > 1:
            t_plot = t[::step]
        else:
            t_plot = t

        names = getattr(self, "channel_names", None)
        multi = len(sel) > 1

        if not multi:
            # === Single-channel: classic amplitude view ===
            ch = sel[0]
            y = X[:, ch]
            if step > 1:
                y = y[::step]

            ax.plot(
                t_plot,
                y,
                lw=1.0,
                color=getattr(self, "graph_color", "#03DFE2"),
            )
            ax.set_ylabel("Amplitude", color="white")
        else:
            # === Multi-channel: stacked lanes (one band per channel) ===
            band_gap = 1.2   # vertical spacing between lanes
            centers = []
            labels = []
            n_sel = len(sel)

            # Build ordered palette: start from current graph_color in color_options
            if hasattr(self, "color_options") and isinstance(self.color_options, dict):
                palette = list(self.color_options.values())
            else:
                palette = [getattr(self, "graph_color", "#03DFE2")]

            base_color = getattr(self, "graph_color", palette[0])
            try:
                base_idx = palette.index(base_color)
            except ValueError:
                base_idx = 0

            for idx, ch in enumerate(sel):
                y = X[:, ch]
                if step > 1:
                    y = y[::step]

                # Normalize per channel so each lane is visible
                y = np.asarray(y, dtype=float)
                y = y - np.mean(y)
                ymin = float(np.min(y))
                ymax = float(np.max(y))
                rng = ymax - ymin
                if rng <= 0:
                    y_scaled = np.zeros_like(y)
                else:
                    # scale to approximately [-0.5, 0.5]
                    y_scaled = (y - (ymin + ymax) / 2.0) / (rng or 1.0)

                center = (n_sel - 1 - idx) * band_gap  # top channel first
                centers.append(center)

                label = (
                    names[ch]
                    if names and ch < len(names)
                    else f"Ch {ch+1}"
                )
                labels.append(label)

                # Choose colour for this channel from palette
                col = palette[(base_idx + idx) % len(palette)]

                ax.plot(
                    t_plot,
                    y_scaled + center,
                    lw=0.9,
                    color=col,
                )

            ax.set_yticks(centers)
            try:
                ax.set_yticklabels(labels, color="white")
            except Exception:
                ax.set_yticklabels(labels)
            ymin = -band_gap * 0.6
            ymax = (n_sel - 1) * band_gap + band_gap * 0.6
            ax.set_ylim(ymin, ymax)
            ax.set_ylabel("Channels", color="white")

        # --- Common cosmetics ---
        if t_plot.size > 0:
            ax.set_xlim(t_plot[0], t_plot[-1])

        ax.set_title("Raw waveform", color="white")
        ax.set_xlabel("Time (s)", color="white")
        ax.tick_params(colors="white")
        for sp in ax.spines.values():
            sp.set_edgecolor("white")

        try:
            self.canvas.draw_idle()
        except Exception:
            self.canvas.draw()




    def _ensure_channel_info(self):
        """Ensure channel count, names, and mask exist."""
        if getattr(self, 'full_data', None) is None:
            return
        try:
            if getattr(self.full_data, 'ndim', 1) > 1:
                self.channels = int(self.full_data.shape[1])
            else:
                self.channels = 1
        except Exception:
            self.channels = 1
        if not hasattr(self, 'channel_names') or len(getattr(self, 'channel_names', [])) != self.channels:
            self.channel_names = [f"Ch {i+1}" for i in range(self.channels)]
        if not hasattr(self, 'channel_mask') or len(getattr(self, 'channel_mask', [])) != self.channels:
            self.channel_mask = [True] * self.channels

        # Keep per-channel configuration aligned with channel count
        if not hasattr(self, "channel_configs") or len(getattr(self, "channel_configs", [])) != self.channels:
            existing = getattr(self, "channel_configs", []) or []
            merged = []
            for i in range(self.channels):
                base = {"mode": "raw", "hydrophone_curve": None, "distance": None, "depth": None, "scale": 1.0, "name": None}
                if i < len(existing) and isinstance(existing[i], dict):
                    base.update({k: v for k, v in existing[i].items() if v is not None})
                merged.append(base)
            self.channel_configs = merged

        # Sync configured names back to channel_names for display
        cfg_names = []
        for i in range(self.channels):
            cfg = self.channel_configs[i] if i < len(self.channel_configs) else {}
            nm = None
            if isinstance(cfg, dict):
                nm = cfg.get("name")
            cfg_names.append(nm if nm else f"Ch {i+1}")
        self.channel_names = cfg_names

    def _default_hydrophone_depth_m(self):
        """Return a single configured hydrophone depth in meters, or None."""
        self._ensure_channel_info()
        depths = []
        for cfg in getattr(self, "channel_configs", []) or []:
            if not isinstance(cfg, dict):
                continue
            if cfg.get("mode") != "hydrophone":
                continue
            val = cfg.get("depth")
            if val in (None, ""):
                continue
            try:
                depths.append(float(val))
            except Exception:
                continue
        if len(depths) == 1:
            return depths[0]
        return None

    def get_channel_data(self, ch_index: int):
        """
        Return a 1-D numpy array for the given channel index.
        Works for mono and multi-channel full_data.
        """
        import numpy as np

        data = getattr(self, "full_data", None)
        if data is None:
            return None

        arr = np.asarray(data)
        if arr.ndim == 1:
            # mono
            return arr if ch_index == 0 else None

        if arr.ndim == 2 and 0 <= ch_index < arr.shape[1]:
            return arr[:, ch_index]

        return None


    def channel_file_label(self, ch_index: int) -> str:
        """
        Build file_name with _chN suffix for logging: myfile_ch1.wav, etc.
        """
        import os
        base_name = getattr(self, "file_name", "") or "measurement"
        base, ext = os.path.splitext(base_name)
        cfg = self._get_channel_config(ch_index) or {}
        alias = cfg.get("name") if isinstance(cfg, dict) else None
        if not alias and hasattr(self, "channel_names") and 0 <= ch_index < len(self.channel_names):
            alias = self.channel_names[ch_index]
        if alias:
            import re
            safe = re.sub(r"[^A-Za-z0-9]+", "_", str(alias)).strip("_")
        else:
            safe = ""
        suffix = f"_ch{ch_index+1}"
        if safe:
            suffix += f"_{safe}"
        return f"{base}{suffix}{ext}"


    def selected_channel_indices(self):
        """Return indices of currently selected channels."""
        self._ensure_channel_info()
        return [i for i, on in enumerate(getattr(self, 'channel_mask', [])) if on]

