        def apply_mains_notch(data):
            choice = mains_combo.currentText()
            if choice == "None":
                return data
            f0 = 50.0 if "50" in choice else 60.0
            bw = 2.0
            low = (f0 - bw / 2.0) / (self.sample_rate / 2.0)
            high = (f0 + bw / 2.0) / (self.sample_rate / 2.0)
            sos = butter(2, [low, high], btype="bandstop", output="sos")
            return safe_sosfiltfilt(sos, data)

        preview_state = {"data": None, "pulse_time": None, "channel_index": 0}
        drag_state = {"active": False, "pulse_index": None, "grab_offset": 0.0}

        def _current_window_length():
            """Window length to use right now (seconds)."""
            try:
                mode_txt = analysis_mode_combo.currentText()
            except Exception:
                mode_txt = "Standard (FFT window)"
            if "Gate" in mode_txt:
                try:
                    return float(gate_len_spin.value())
                except Exception:
                    return float(window_length)
            return float(window_length)


        # ── Smart tools helpers ─────────────────────────────────────────────
        def _smart_channel_index():
            try:
                sel = self.selected_channel_indices() if hasattr(self, "selected_channel_indices") else [0]
                return int(sel[0]) if sel else 0
            except Exception:
                return 0

        def _window_segment(t0, wl):
            """Return (seg, fs, ch_idx) for the current channel and window."""
            fs = float(getattr(self, "sample_rate", None) or getattr(self, "samplerate", None) or 0)
            if fs <= 0 or self.full_data is None:
                return None, None, None
            ch = _smart_channel_index()
            x = self.get_channel_data(ch) if hasattr(self, "get_channel_data") else None
            if x is None:
                import numpy as np
                arr = np.asarray(self.full_data)
                x = arr if arr.ndim == 1 else arr[:, ch]
            i0 = int(max(0, round(t0 * fs)))
            i1 = int(min(len(x), round((t0 + wl) * fs)))
            if i1 <= i0 + 1:
                return None, fs, ch
            import numpy as np
            seg = np.asarray(x[i0:i1], dtype=float)
            return seg, fs, ch

        def _estimate_snr(seg, fs):
            """Simple SNR estimate: compare window RMS vs pre-window noise RMS."""
            try:
                wl = len(seg)
                npre = int(min(wl, max(8, round(0.25 * wl))))
                # take a short leading slice as noise proxy if we don't have pre-window samples
                noise = seg[:npre]
                import numpy as np
                rms_sig = float(np.sqrt(np.mean(seg * seg))) if wl > 0 else 0.0
                rms_n = float(np.sqrt(np.mean(noise * noise))) if npre > 0 else 0.0
                if rms_n <= 1e-12:
                    return 99.0
                return 20.0 * math.log10(max(rms_sig, 1e-12) / max(rms_n, 1e-12))
            except Exception:
                return None

        def _features_for_window(t0, wl, freq_est=None):
            seg, fs, ch = _window_segment(t0, wl)
            if seg is None:
                return None
            import numpy as np
            seg = seg - float(np.mean(seg))
            rms = float(np.sqrt(np.mean(seg * seg)))
            peak = float(np.max(np.abs(seg)))
            crest = float(peak / rms) if rms > 1e-12 else None

            # If caller didn't provide freq, do a quick FFT peak
            if freq_est is None and fs and len(seg) > 8:
                win = np.hanning(len(seg))
                sp = np.fft.rfft(seg * win)
                freqs = np.fft.rfftfreq(len(seg), d=1.0 / fs)
                k = int(np.argmax(np.abs(sp)))
                freq_est = float(freqs[k]) if k < len(freqs) else None

            snr_db = _estimate_snr(seg, fs)

            return {
                "channel_index": int(ch),
                "t_start": float(t0),
                "t_end": float(t0 + wl),
                "t_peak": float(t0 + (np.argmax(np.abs(seg)) / fs)) if fs else float(t0),
                "window_length": float(wl),
                "rms": rms,
                "peak": peak,
                "crest": crest,
                "freq_est": float(freq_est) if freq_est is not None else None,
                "snr": snr_db,
            }

        def _ensure_pulse_tables():
            # Tables are created in init_db(), but older DBs might exist
            try:
                conn = sqlite3.connect(DB_FILENAME)
                cur = conn.cursor()
                cur.execute(
                    """CREATE TABLE IF NOT EXISTS pulse_events (
                        event_id TEXT PRIMARY KEY,
                        file_name TEXT,
                        channel_index INTEGER,
                        t_start REAL, t_end REAL, t_peak REAL,
                        window_length REAL,
                        rms REAL, peak REAL, crest REAL,
                        freq_est REAL, snr REAL,
                        label TEXT, confidence REAL, anomaly_score REAL,
                        detector TEXT, gate_mode TEXT,
                        created_at DATETIME DEFAULT CURRENT_TIMESTAMP
                    )"""
                )
                cur.execute(
                    """CREATE TABLE IF NOT EXISTS pulse_models (
                        id INTEGER PRIMARY KEY AUTOINCREMENT,
                        name TEXT,
                        file_scope TEXT,
                        model_path TEXT,
                        feature_list_json TEXT,
                        label_list_json TEXT,
                        created_at DATETIME DEFAULT CURRENT_TIMESTAMP
                    )"""
                )
                conn.commit()
                conn.close()
            except Exception:
                pass

        def _event_id_for(t0, wl, ch):
            base = f"{self.file_name}|{ch}|{t0:.9f}|{wl:.9f}"
            return hashlib.sha1(base.encode("utf-8")).hexdigest()

        def _upsert_event(feat, label=None, confidence=None, anomaly_score=None, detector="auto", gate_mode=None):
            _ensure_pulse_tables()
            if feat is None:
                return None
            eid = _event_id_for(feat["t_start"], feat["window_length"], feat["channel_index"])
            try:
                conn = sqlite3.connect(DB_FILENAME)
                cur = conn.cursor()
                cur.execute(
                    """INSERT INTO pulse_events
                        (event_id, file_name, channel_index, t_start, t_end, t_peak, window_length,
                         rms, peak, crest, freq_est, snr, label, confidence, anomaly_score, detector, gate_mode)
                       VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
                       ON CONFLICT(event_id) DO UPDATE SET
                         rms=excluded.rms,
                         peak=excluded.peak,
                         crest=excluded.crest,
                         freq_est=excluded.freq_est,
                         snr=excluded.snr,
                         label=COALESCE(excluded.label, pulse_events.label),
                         confidence=COALESCE(excluded.confidence, pulse_events.confidence),
                         anomaly_score=COALESCE(excluded.anomaly_score, pulse_events.anomaly_score),
                         detector=excluded.detector,
                         gate_mode=COALESCE(excluded.gate_mode, pulse_events.gate_mode)
                    """,
                    (
                        eid, self.file_name, int(feat["channel_index"]),
                        float(feat["t_start"]), float(feat["t_end"]), float(feat["t_peak"]),
                        float(feat["window_length"]),
                        feat.get("rms"), feat.get("peak"), feat.get("crest"),
                        feat.get("freq_est"), feat.get("snr"),
                        label, confidence, anomaly_score,
                        detector, gate_mode,
                    ),
                )
                conn.commit()
                conn.close()
                return eid
            except Exception:
                return None

        
        def _label_current(label_text):
            try:
                wl = float(_current_window_length())
                t0 = float(current_window_start)
            except Exception:
                return
            # Optional: use the currently displayed frequency if available
            freq_guess = None
            try:
                freq_guess = float(freq_label.text().split()[0])  # e.g. "90000.0 Hz"
            except Exception:
                freq_guess = None
            feat = _features_for_window(t0, wl, freq_est=freq_guess)
            gate_mode = None
            try:
                gate_mode = str(mode_combo.currentText())
            except Exception:
                gate_mode = None
            _upsert_event(feat, label=str(label_text), detector="manual_label", gate_mode=gate_mode)
            try:
                status_label.setText(f"Labeled: {label_text} @ {t0:.6f}s")
            except Exception:
                pass

        def _fetch_labeled_rows():
            _ensure_pulse_tables()
            conn = sqlite3.connect(DB_FILENAME)
            cur = conn.cursor()
            cur.execute(
                """SELECT rms, peak, crest, freq_est, snr, window_length, label
                   FROM pulse_events
                   WHERE file_name=? AND label IS NOT NULL AND label<>''""",
                (self.file_name,),
            )
            rows = cur.fetchall()
            conn.close()
            return rows

        def _train_classifier():
            rows = _fetch_labeled_rows()
            if len(rows) < 10:
                QtWidgets.QMessageBox.information(dlg, "Need more labels", "Please label at least ~10 pulses before training.")
                return None
            X = []
            y = []
            for r in rows:
                rms, peak, crest, freq_est, snr, wl_, lab = r
                if rms is None or peak is None or freq_est is None:
                    continue
                X.append([float(rms), float(peak), float(crest or 0.0), float(freq_est), float(snr or 0.0), float(wl_ or 0.0)])
                y.append(str(lab))
            if len(set(y)) < 2:
                QtWidgets.QMessageBox.information(dlg, "Need 2 classes", "Please label at least two different classes before training.")
                return None
            try:
                from sklearn.pipeline import Pipeline
                from sklearn.preprocessing import StandardScaler
                from sklearn.linear_model import LogisticRegression
                model = Pipeline([
                    ("scaler", StandardScaler()),
                    ("clf", LogisticRegression(max_iter=2000)),
                ])
                model.fit(X, y)
            except Exception as e:
                QtWidgets.QMessageBox.critical(dlg, "Training failed", f"Training failed:\n{e}")
                return None

            # Save model into project dir if available
            out_dir = getattr(self, "current_project_dir", None) or os.getcwd()
            model_dir = os.path.join(out_dir, "models")
            os.makedirs(model_dir, exist_ok=True)
            base = os.path.splitext(os.path.basename(self.file_name or "file"))[0]
            model_path = os.path.join(model_dir, f"{base}_pulse_classifier.joblib")
            try:
                joblib.dump(model, model_path)
            except Exception:
                pass

            # Record in DB
            try:
                conn = sqlite3.connect(DB_FILENAME)
                cur = conn.cursor()
                feat_list = ["rms","peak","crest","freq_est","snr","window_length"]
                lbl_list = sorted(list(set(y)))
                cur.execute(
                    """INSERT INTO pulse_models (name, file_scope, model_path, feature_list_json, label_list_json)
                       VALUES (?,?,?,?,?)""",
                    (f"{base}_pulse_classifier", self.file_name, model_path, json.dumps(feat_list), json.dumps(lbl_list)),
                )
                conn.commit(); conn.close()
            except Exception:
                pass

            QtWidgets.QMessageBox.information(dlg, "Trained", f"Classifier trained on {len(y)} labeled pulses.\nSaved: {model_path}")
            return model_path

        def _load_latest_model():
            _ensure_pulse_tables()
            conn = sqlite3.connect(DB_FILENAME)
            cur = conn.cursor()
            cur.execute(
                """SELECT model_path FROM pulse_models
                   WHERE file_scope=? ORDER BY id DESC LIMIT 1""",
                (self.file_name,),
            )
            row = cur.fetchone()
            conn.close()
            if not row:
                return None
            p = row[0]
            if p and os.path.exists(p):
                return p
            return None

        def _apply_classifier():
            model_path = _load_latest_model()
            if not model_path:
                QtWidgets.QMessageBox.information(dlg, "No model", "No trained model found for this file. Click 'Train classifier' first.")
                return
            try:
                model = joblib.load(model_path)
            except Exception as e:
                QtWidgets.QMessageBox.critical(dlg, "Load failed", f"Could not load model:\n{e}")
                return

            # Apply to all pulses (current channel)
            ch = _smart_channel_index()
            wl = float(_current_window_length())
            gate_mode = str(mode_combo.currentText()) if 'mode_combo' in locals() else None
            applied = 0
            for idx in range(int(len(self.pulse_indices))):
                t0 = float(self.full_time[self.pulse_indices[idx]])
                feat = _features_for_window(t0, wl)
                if not feat:
                    continue
                X = [[float(feat["rms"]), float(feat["peak"]), float(feat["crest"] or 0.0),
                      float(feat["freq_est"] or 0.0), float(feat["snr"] or 0.0), float(feat["window_length"] or 0.0)]]
                try:
                    proba = model.predict_proba(X)[0]
                    labs = list(model.classes_)
                    j = int(np.argmax(proba))
                    lab = str(labs[j])
                    conf = float(proba[j])
                except Exception:
                    lab = str(model.predict(X)[0])
                    conf = None
                _upsert_event(feat, label=lab, confidence=conf, detector="classifier", gate_mode=gate_mode)
                applied += 1
            QtWidgets.QMessageBox.information(dlg, "Applied", f"Applied classifier to {applied} pulses.\n(Results saved to DB)")

        def _find_anomalies():
            # Use currently computed/available features for all pulses
            wl = float(_current_window_length())
            feats = []
            ids = []
            gate_mode = str(mode_combo.currentText()) if 'mode_combo' in locals() else None
            for idx in range(int(len(self.pulse_indices))):
                t0 = float(self.full_time[self.pulse_indices[idx]])
                feat = _features_for_window(t0, wl)
                if not feat or feat.get("freq_est") is None:
                    continue
                X = [float(feat["rms"]), float(feat["peak"]), float(feat["crest"] or 0.0),
                     float(feat["freq_est"] or 0.0), float(feat["snr"] or 0.0), float(feat["window_length"] or 0.0)]
                feats.append(X)
                ids.append((feat, gate_mode))
            if len(feats) < 20:
                QtWidgets.QMessageBox.information(dlg, "Not enough pulses", "Need at least ~20 pulses to run anomaly detection.")
                return
            try:
                from sklearn.ensemble import IsolationForest
                contam = float(anom_pct.value()) / 100.0
                iso = IsolationForest(contamination=max(0.001, min(0.2, contam)), random_state=0)
                iso.fit(feats)
                # Higher is "more anomalous"
                score = -iso.score_samples(feats)
            except Exception as e:
                QtWidgets.QMessageBox.critical(dlg, "Anomaly failed", f"Anomaly detection failed:\n{e}")
                return

            # Save to DB and report top 10
            order = np.argsort(score)[::-1]
            top = order[:10]
            lines = []
            for k in top:
                feat, gm = ids[int(k)]
                sc = float(score[int(k)])
                _upsert_event(feat, anomaly_score=sc, detector="anomaly", gate_mode=gm)
                lines.append(f"{feat['t_start']:.6f}s  score={sc:.3f}")
            QtWidgets.QMessageBox.information(dlg, "Top anomalies", "Top anomaly windows:\n\n" + "\n".join(lines))


