    def _wav_project_modified_dir(self) -> str:
        """Return <project>/modified folder (and create it)."""
        import os
        out_dir = self._project_subdir("modified")
        if not out_dir:
            return ""
        os.makedirs(out_dir, exist_ok=True)
        return out_dir

    def wav_inspector_popup(self):
        """Inspect WAV format + basic stats for one or more files."""
        import os
        import numpy as np

        try:
            import soundfile as sf
        except Exception:
            sf = None

        start_dir = self._dialog_default_dir("originals") or os.getcwd()
        files, _ = QtWidgets.QFileDialog.getOpenFileNames(
            self, "Select WAV file(s) to inspect", start_dir, "WAV Files (*.wav);;All Files (*.*)"
        )
        if not files:
            return

        dlg = QtWidgets.QDialog(self)
        dlg.setWindowTitle("WAV Inspector (Format + Stats)")
        dlg.resize(900, 460)
        lay = QtWidgets.QVBoxLayout(dlg)

        note = QtWidgets.QLabel("Shows detected encoding (PCM/FLOAT), sample rate, channels, duration, peak, RMS, DC.")
        note.setWordWrap(True)
        lay.addWidget(note)

        tbl = QtWidgets.QTableWidget(0, 9)
        tbl.setHorizontalHeaderLabels([
            "File", "Type", "SR", "Ch", "Duration (s)", "Frames", "Peak", "RMS", "DC"
        ])
        tbl.horizontalHeader().setStretchLastSection(True)
        lay.addWidget(tbl, 1)

        btns = QtWidgets.QHBoxLayout()
        btns.addStretch(1)
        close_btn = QtWidgets.QPushButton("Close")
        btns.addWidget(close_btn)
        lay.addLayout(btns)
        close_btn.clicked.connect(dlg.accept)

        rows = []
        for p in files:
            base = os.path.basename(p)
            try:
                if sf is None:
                    # fallback: minimal info only
                    import wave
                    with wave.open(p, 'rb') as wf:
                        sr = wf.getframerate()
                        ch = wf.getnchannels()
                        frames = wf.getnframes()
                    rows.append((base, "(no soundfile)", sr, ch, frames / max(sr, 1), frames, "", "", ""))
                    continue

                info = sf.info(p)
                data, sr = sf.read(p, dtype='float32', always_2d=True)
                frames = data.shape[0]
                ch = data.shape[1]
                dur = frames / float(sr) if sr else 0.0
                peak = float(np.max(np.abs(data))) if data.size else 0.0
                rms = float(np.sqrt(np.mean(np.square(data)))) if data.size else 0.0
                dc = float(np.mean(data)) if data.size else 0.0
                rows.append((base, info.subtype, sr, ch, dur, frames, peak, rms, dc))
            except Exception as e:
                rows.append((base, f"ERROR: {e}", "", "", "", "", "", "", ""))

        tbl.setRowCount(len(rows))
        for r, row in enumerate(rows):
            for c, val in enumerate(row):
                item = QtWidgets.QTableWidgetItem(str(val))
                item.setFlags(item.flags() & ~QtCore.Qt.ItemIsEditable)
                tbl.setItem(r, c, item)

        dlg.exec_()

    def pcm16_converter_popup(self):
        """Detect WAV encoding and convert to PCM16 into <project>/modified."""
        import os
        import numpy as np

        out_dir = self._wav_project_modified_dir()
        if not out_dir:
            QtWidgets.QMessageBox.warning(self, "Select Project", "Please select a Project first.")
            return

        try:
            import soundfile as sf
        except Exception as e:
            QtWidgets.QMessageBox.critical(
                self, "Missing Dependency",
                "The 'soundfile' library is required for robust WAV conversion (FLOAT/PCM24/etc).\n"
                "Install it with: pip install soundfile\n\n"
                f"Error: {e}"
            )
            return

        start_dir = self._dialog_default_dir("originals") or os.getcwd()
        files, _ = QtWidgets.QFileDialog.getOpenFileNames(
            self, "Select WAV file(s) to convert to PCM16", start_dir, "WAV Files (*.wav);;All Files (*.*)"
        )
        if not files:
            return

        dlg = QtWidgets.QDialog(self)
        dlg.setWindowTitle("Convert to PCM16 (Detect + Convert)")
        dlg.resize(920, 520)
        lay = QtWidgets.QVBoxLayout(dlg)

        info = QtWidgets.QLabel(
            "Outputs are written into the selected project's /modified folder.\n"
            "Output naming: <name>_pcm16.wav\n"
            f"Folder: {out_dir}"
        )
        info.setWordWrap(True)
        lay.addWidget(info)

        opts = QtWidgets.QHBoxLayout()
        overwrite_cb = QtWidgets.QCheckBox("Overwrite if exists")
        overwrite_cb.setChecked(False)
        normalize_cb = QtWidgets.QCheckBox("Auto-normalize if peak > 1.0 (avoid clipping)")
        normalize_cb.setChecked(True)
        autoload_cb = QtWidgets.QCheckBox("Auto-load output (only if 1 file)")
        autoload_cb.setChecked(True)
        opts.addWidget(overwrite_cb)
        opts.addWidget(normalize_cb)
        opts.addWidget(autoload_cb)
        opts.addStretch(1)
        lay.addLayout(opts)

        tbl = QtWidgets.QTableWidget(0, 5)
        tbl.setHorizontalHeaderLabels(["File", "Detected Type", "SR", "Ch", "Status"]) 
        tbl.horizontalHeader().setStretchLastSection(True)
        lay.addWidget(tbl, 1)

        log_box = QtWidgets.QPlainTextEdit()
        log_box.setReadOnly(True)
        log_box.setMaximumBlockCount(2000)
        lay.addWidget(log_box, 1)

        btns = QtWidgets.QHBoxLayout()
        btns.addStretch(1)
        run_btn = QtWidgets.QPushButton("Convert")
        close_btn = QtWidgets.QPushButton("Close")
        btns.addWidget(run_btn)
        btns.addWidget(close_btn)
        lay.addLayout(btns)
        close_btn.clicked.connect(dlg.reject)

        def log(msg):
            log_box.appendPlainText(msg)

        # populate table
        tbl.setRowCount(len(files))
        for r, p in enumerate(files):
            base = os.path.basename(p)
            try:
                inf = sf.info(p)
                subtype = inf.subtype
                sr = inf.samplerate
                ch = inf.channels
            except Exception as e:
                subtype = f"ERROR: {e}"
                sr = ""
                ch = ""
            tbl.setItem(r, 0, QtWidgets.QTableWidgetItem(base))
            tbl.setItem(r, 1, QtWidgets.QTableWidgetItem(str(subtype)))
            tbl.setItem(r, 2, QtWidgets.QTableWidgetItem(str(sr)))
            tbl.setItem(r, 3, QtWidgets.QTableWidgetItem(str(ch)))
            tbl.setItem(r, 4, QtWidgets.QTableWidgetItem("Pending"))

        def float_to_pcm16(x: np.ndarray) -> np.ndarray:
            x = np.clip(x, -1.0, 1.0)
            return (x * 32767.0).round().astype(np.int16)

        def set_status(row, status):
            tbl.setItem(row, 4, QtWidgets.QTableWidgetItem(status))

        def do_convert():
            run_btn.setEnabled(False)
            ok = 0
            last_out = None
            try:
                for r, p in enumerate(files):
                    base = os.path.splitext(os.path.basename(p))[0]
                    outp = os.path.join(out_dir, f"{base}_pcm16.wav")
                    try:
                        if os.path.exists(outp) and not overwrite_cb.isChecked():
                            raise RuntimeError("Output exists (enable overwrite)")

                        data, sr = sf.read(p, dtype='float32', always_2d=True)
                        if data.size == 0:
                            raise RuntimeError("No samples")

                        if normalize_cb.isChecked():
                            peak = float(np.max(np.abs(data)))
                            if peak > 1.0:
                                data = data / peak
                                log(f"{os.path.basename(p)}: normalized peak {peak:.3f} -> 1.000")

                        pcm16 = float_to_pcm16(data)
                        sf.write(outp, pcm16, sr, subtype='PCM_16')

                        set_status(r, "OK")
                        ok += 1
                        last_out = outp
                        log(f"Wrote: {outp}")
                    except Exception as e:
                        set_status(r, f"ERROR")
                        log(f"ERROR {os.path.basename(p)}: {e}")

            finally:
                run_btn.setEnabled(True)

            QtWidgets.QMessageBox.information(
                dlg, "Done",
                f"Converted {ok}/{len(files)} file(s) to PCM16.\n\nFolder:\n{out_dir}"
            )

            if ok == 1 and autoload_cb.isChecked() and last_out:
                # Load into app if a loader exists
                for cand in ("load_wav_file", "open_file", "load_file"):
                    if hasattr(self, cand):
                        try:
                            getattr(self, cand)(last_out)
                        except Exception:
                            pass
                        break

        run_btn.clicked.connect(do_convert)
        dlg.exec_()

    def wav_batch_standardize_popup(self):
        """Batch standardize WAVs into project/modified: PCM16 + optional resample."""
        import os
        import numpy as np

        out_dir = self._wav_project_modified_dir()
        if not out_dir:
            QtWidgets.QMessageBox.warning(self, "Select Project", "Please select a Project first.")
            return

        try:
            import soundfile as sf
        except Exception as e:
            QtWidgets.QMessageBox.critical(self, "Missing Dependency", f"Requires soundfile.\n{e}")
            return

        try:
            from scipy.signal import resample_poly
        except Exception:
            resample_poly = None

        start_dir = self._dialog_default_dir("originals") or os.getcwd()
        files, _ = QtWidgets.QFileDialog.getOpenFileNames(
            self, "Select WAV file(s) to standardize", start_dir, "WAV Files (*.wav);;All Files (*.*)"
        )
        if not files:
            return

        dlg = QtWidgets.QDialog(self)
        dlg.setWindowTitle("Batch Standardize WAVs (PCM16 + SR)")
        dlg.resize(900, 520)
        lay = QtWidgets.QVBoxLayout(dlg)

        form = QtWidgets.QFormLayout()
        sr_cb = QtWidgets.QComboBox()
        sr_cb.addItem("Keep original sample rate", userData=None)
        for sr in (8000, 16000, 24000, 32000, 44100, 48000, 96000, 192000):
            sr_cb.addItem(str(sr), userData=int(sr))
        form.addRow("Target Sample Rate:", sr_cb)

        overwrite_cb = QtWidgets.QCheckBox("Overwrite if exists")
        overwrite_cb.setChecked(False)
        form.addRow("", overwrite_cb)

        if resample_poly is None:
            warn = QtWidgets.QLabel("NOTE: scipy not available → resample disabled (PCM16 conversion only).")
            warn.setStyleSheet("color:#ffcccc;")
            lay.addWidget(warn)

        lay.addLayout(form)

        log_box = QtWidgets.QPlainTextEdit()
        log_box.setReadOnly(True)
        log_box.setMaximumBlockCount(4000)
        lay.addWidget(log_box, 1)

        btns = QtWidgets.QHBoxLayout()
        btns.addStretch(1)
        run_btn = QtWidgets.QPushButton("Run")
        close_btn = QtWidgets.QPushButton("Close")
        btns.addWidget(run_btn)
        btns.addWidget(close_btn)
        lay.addLayout(btns)
        close_btn.clicked.connect(dlg.reject)

        def log(msg):
            log_box.appendPlainText(msg)

        def float_to_pcm16(x: np.ndarray) -> np.ndarray:
            x = np.clip(x, -1.0, 1.0)
            return (x * 32767.0).round().astype(np.int16)

        def do_run():
            target_sr = sr_cb.currentData()
            ok = 0
            for p in files:
                base = os.path.splitext(os.path.basename(p))[0]
                sr_tag = f"sr{target_sr}" if target_sr else "srkeep"
                outp = os.path.join(out_dir, f"{base}_{sr_tag}_pcm16.wav")
                try:
                    if os.path.exists(outp) and not overwrite_cb.isChecked():
                        raise RuntimeError("Output exists")

                    data, sr = sf.read(p, dtype='float32', always_2d=True)
                    if data.size == 0:
                        raise RuntimeError("No samples")

                    # resample if requested
                    if target_sr and (int(sr) != int(target_sr)):
                        if resample_poly is None:
                            raise RuntimeError("scipy missing: cannot resample")
                        # choose integer up/down factors using gcd
                        import math
                        g = math.gcd(int(sr), int(target_sr))
                        up = int(target_sr) // g
                        down = int(sr) // g
                        # resample each channel
                        res = []
                        for c in range(data.shape[1]):
                            res.append(resample_poly(data[:, c], up, down))
                        data = np.stack(res, axis=1)
                        sr = int(target_sr)
                        log(f"{os.path.basename(p)}: resampled {int(sf.info(p).samplerate)} -> {sr}")

                    pcm16 = float_to_pcm16(data)
                    sf.write(outp, pcm16, int(sr), subtype='PCM_16')
                    ok += 1
                    log(f"OK: {outp}")
                except Exception as e:
                    log(f"ERROR {os.path.basename(p)}: {e}")

            QtWidgets.QMessageBox.information(dlg, "Done", f"Standardized {ok}/{len(files)} file(s).\n\n{out_dir}")

        run_btn.clicked.connect(do_run)
        dlg.exec_()

    def wav_dc_clipping_report_popup(self):
        """Compute DC offset + clipping stats for WAVs; optionally export CSV into project/modified."""
        import os
        import numpy as np
        import csv

        try:
            import soundfile as sf
        except Exception as e:
            QtWidgets.QMessageBox.critical(self, "Missing Dependency", f"Requires soundfile.\n{e}")
            return

        start_dir = self._dialog_default_dir("originals") or os.getcwd()
        files, _ = QtWidgets.QFileDialog.getOpenFileNames(
            self, "Select WAV file(s) for DC/Clipping report", start_dir, "WAV Files (*.wav);;All Files (*.*)"
        )
        if not files:
            return

        dlg = QtWidgets.QDialog(self)
        dlg.setWindowTitle("DC Offset + Clipping Report")
        dlg.resize(980, 520)
        lay = QtWidgets.QVBoxLayout(dlg)

        tbl = QtWidgets.QTableWidget(0, 9)
        tbl.setHorizontalHeaderLabels([
            "File", "Type", "SR", "Ch", "Duration(s)", "Peak", "DC", "Clip%", "Notes"
        ])
        tbl.horizontalHeader().setStretchLastSection(True)
        lay.addWidget(tbl, 1)

        btns = QtWidgets.QHBoxLayout()
        export_btn = QtWidgets.QPushButton("Export CSV to project/modified")
        close_btn = QtWidgets.QPushButton("Close")
        btns.addWidget(export_btn)
        btns.addStretch(1)
        btns.addWidget(close_btn)
        lay.addLayout(btns)
        close_btn.clicked.connect(dlg.accept)

        rows = []
        for p in files:
            base = os.path.basename(p)
            try:
                inf = sf.info(p)
                data, sr = sf.read(p, dtype='float32', always_2d=True)
                frames = data.shape[0]
                ch = data.shape[1]
                dur = frames / float(sr) if sr else 0.0
                peak = float(np.max(np.abs(data))) if data.size else 0.0
                dc = float(np.mean(data)) if data.size else 0.0
                # clipping threshold: for float assume > 0.9999, for PCM read-as-float still OK
                clip_thr = 0.9999
                clip_pct = float(np.mean(np.abs(data) >= clip_thr) * 100.0) if data.size else 0.0
                note = ""
                if peak > 1.0:
                    note = "peak>1.0 (float overflow)"
                elif clip_pct > 0.01:
                    note = "clipping detected"
                rows.append([base, inf.subtype, sr, ch, f"{dur:.3f}", f"{peak:.4f}", f"{dc:.6f}", f"{clip_pct:.4f}", note])
            except Exception as e:
                rows.append([base, f"ERROR: {e}", "", "", "", "", "", "", ""]) 

        tbl.setRowCount(len(rows))
        for r, row in enumerate(rows):
            for c, val in enumerate(row):
                it = QtWidgets.QTableWidgetItem(str(val))
                it.setFlags(it.flags() & ~QtCore.Qt.ItemIsEditable)
                tbl.setItem(r, c, it)

        def do_export():
            out_dir = self._wav_project_modified_dir()
            if not out_dir:
                QtWidgets.QMessageBox.warning(self, "Select Project", "Select a Project first to export into /modified.")
                return
            outp = os.path.join(out_dir, "wav_dc_clipping_report.csv")
            try:
                with open(outp, 'w', newline='', encoding='utf-8') as f:
                    w = csv.writer(f)
                    w.writerow(["file", "type", "sr", "channels", "duration_s", "peak", "dc", "clip_percent", "notes"])
                    for row in rows:
                        w.writerow(row)
                QtWidgets.QMessageBox.information(dlg, "Exported", f"Wrote:\n{outp}")
            except Exception as e:
                QtWidgets.QMessageBox.critical(dlg, "Export failed", str(e))

        export_btn.clicked.connect(do_export)
        dlg.exec_()

